import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.http.HttpStatus;
import java.util.List;

// 1. @RestController combines @Controller and @ResponseBody
// It ensures returned objects are automatically serialized to JSON.
@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService service;
    public UserController(UserService service) { this.service = service; }

    // GET /api/users
    @GetMapping
    public List<User> getAllUsers() {
        return service.findAll();
    }

    // GET /api/users/123 (Path Variable)
    @GetMapping("/{id}")
    public ResponseEntity<User> getUserById(@PathVariable Long id) {
        User user = service.findById(id);
        if (user == null) {
            return ResponseEntity.notFound().build(); // 404
        }
        return ResponseEntity.ok(user); // 200
    }

    // POST /api/users (Request Body deserialized from JSON)
    @PostMapping
    public ResponseEntity<User> createUser(@RequestBody User newUser) {
        User saved = service.save(newUser);
        return ResponseEntity.status(HttpStatus.CREATED).body(saved); // 201
    }
}

